mapper.sql:
select id, subtask_id, sequence, protocol, commands, params, status, created_at, updated_at, task_id, remark, device_id, message_event, event_logic from instructions


        and id = #{ew.id}


        and subtask_id = #{ew.subtaskId}


        and sequence = #{ew.sequence}


        and protocol = #{ew.protocol}


        and commands = #{ew.commands}


        and params = #{ew.params}


        and status = #{ew.status}


        and created_at = #{ew.createdAt}


        and updated_at = #{ew.updatedAt}


        and task_id = #{ew.taskId}


        and remark = #{ew.remark}


        and device_id = #{ew.deviceId}


        and message_event = #{ew.messageEvent}


        and event_logic = #{ew.eventLogic}


order by sequence

choose.when:
INSERT INTO instructions (task_id, subtask_id, sequence, protocol, device_id, commands, params, status, remark, message_event, created_at, updated_at, event_logic) SELECT * FROM (VALUES
(#{item.taskId}, #{item.subtaskId}, #{item.sequence}, #{item.protocol}, #{item.deviceId}, #{item.commands, typeHandler=cn.aitplus.wcs.infra.config.CommandListTypeHandler}, #{item.params}, #{item.status}, #{item.remark}, #{item.messageEvent}, #{item.createdAt,jdbcType=TIMESTAMP}, #{item.updatedAt,jdbcType=TIMESTAMP}, #{item.eventLogic,jdbcType=VARCHAR})
) AS t(task_id, subtask_id, sequence, protocol, device_id, commands, params, status, remark, message_event, created_at, updated_at, event_logic) WHERE NOT EXISTS ( SELECT 1 FROM instructions i WHERE i.subtask_id = t.subtask_id AND i.sequence = t.sequence )
